module top_module(
    input clk,
    input rst,
    input load,
    input inc,
    input dec,
    input [3:0] data,
    output [3:0] count
);reg [3:0] obf_count_reg;

always @(posedge clk) begin
    if (rst) begin
        obf_count_reg <= 4'b0000;
    end else if (load) begin
        obf_count_reg <= data;
    end else if (inc) begin
        if (obf_count_reg == 4'b1111) begin
            obf_count_reg <= 4'b0000;
        end else begin
            obf_count_reg <= obf_count_reg + 1;
        end
    end else if (dec) begin
        if (obf_count_reg == 4'b0000) begin
            obf_count_reg <= 4'b1111;
        end else begin
            obf_count_reg <= obf_count_reg - 1;
        end
    end
end

assign count = obf_count_reg;

endmodule
